//! In-memory **liquid shard** — byte pool + JSON commands over AeonFlow payloads.
//!
//! Intended mapping: FPGA fabric holds BRAM/DDR-backed pools; the host speaks the same
//! **10-byte AeonFlow** framing as mesh fat-station / `FlowCodec` so header overhead stays fixed.

use serde_json::{json, Value};

/// Command stream id reserved for gnosis liquid-memory shard mock (host→shard).
pub const STREAM_LIQUID_SHARD_CMD: u16 = 0xF001;
/// Reply stream id (shard→host).
pub const STREAM_LIQUID_SHARD_RSP: u16 = 0xF002;

fn hex_decode(s: &str) -> Result<Vec<u8>, String> {
    if s.len() % 2 != 0 {
        return Err("hex length must be even".into());
    }
    let mut out = Vec::with_capacity(s.len() / 2);
    let b = s.as_bytes();
    let mut i = 0;
    while i < b.len() {
        let hi = from_hex_digit(b[i])?;
        let lo = from_hex_digit(b[i + 1])?;
        out.push((hi << 4) | lo);
        i += 2;
    }
    Ok(out)
}

fn from_hex_digit(c: u8) -> Result<u8, String> {
    match c {
        b'0'..=b'9' => Ok(c - b'0'),
        b'a'..=b'f' => Ok(c - b'a' + 10),
        b'A'..=b'F' => Ok(c - b'A' + 10),
        _ => Err(format!("invalid hex digit: {}", c as char)),
    }
}

fn hex_encode(data: &[u8]) -> String {
    const HEX: &[u8; 16] = b"0123456789abcdef";
    let mut s = String::with_capacity(data.len() * 2);
    for &x in data {
        s.push(HEX[(x >> 4) as usize] as char);
        s.push(HEX[(x & 0xf) as usize] as char);
    }
    s
}

/// Execute one JSON command against `store`, returning a JSON response string.
pub fn handle_command_json(store: &mut [u8], body: &str) -> Result<String, String> {
    let v: Value = serde_json::from_str(body).map_err(|e| e.to_string())?;
    let op = v
        .get("op")
        .and_then(|x| x.as_str())
        .ok_or_else(|| "missing op".to_string())?;

    match op {
        "ping" => Ok(json!({"ok": true, "op": "ping"}).to_string()),
        "stats" => Ok(json!({
            "ok": true,
            "op": "stats",
            "bytes": store.len()
        })
        .to_string()),
        "read" => {
            let offset = v
                .get("offset")
                .and_then(|x| x.as_u64())
                .ok_or_else(|| "read needs offset".to_string())? as usize;
            let len = v
                .get("len")
                .and_then(|x| x.as_u64())
                .ok_or_else(|| "read needs len".to_string())? as usize;
            if offset.saturating_add(len) > store.len() {
                return Err("read out of bounds".into());
            }
            let slice = &store[offset..offset + len];
            Ok(json!({
                "ok": true,
                "op": "read",
                "hex": hex_encode(slice)
            })
            .to_string())
        }
        "write" => {
            let offset = v
                .get("offset")
                .and_then(|x| x.as_u64())
                .ok_or_else(|| "write needs offset".to_string())? as usize;
            let hex = v
                .get("hex")
                .and_then(|x| x.as_str())
                .ok_or_else(|| "write needs hex".to_string())?;
            let bytes = hex_decode(hex)?;
            if offset.saturating_add(bytes.len()) > store.len() {
                return Err("write out of bounds".into());
            }
            store[offset..offset + bytes.len()].copy_from_slice(&bytes);
            Ok(json!({
                "ok": true,
                "op": "write",
                "written": bytes.len()
            })
            .to_string())
        }
        _ => Err(format!("unknown op: {op}")),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn read_write_roundtrip() {
        let mut mem = vec![0u8; 256];
        handle_command_json(&mut mem, r#"{"op":"write","offset":10,"hex":"414243"}"#).unwrap();
        let r = handle_command_json(&mut mem, r#"{"op":"read","offset":10,"len":3}"#).unwrap();
        let v: Value = serde_json::from_str(&r).unwrap();
        assert_eq!(v["hex"], "414243");
    }
}
